const input = $input.first().json;
const prompts = {
  code: `Generate ServiceNow ${input.code_type || 'GlideRecord'} code for: ${input.prompt}. Return only the code, no markdown.`,
  lint: `Review this ServiceNow script for bugs, performance issues, and best practices. Script type: ${input.script_type || 'server'}

${input.script}

Return JSON: {issues: [{severity, message, fix}], score: 0-100, summary: string}`,
  error: `Analyze this ServiceNow error: ${input.error_message}
Context: ${input.context || 'none'}

Return JSON: {title, description, root_cause, fix_steps: [string], severity, category}`,
  query: `Optimize this ServiceNow GlideRecord query for better performance:
${input.script}
Table: ${input.table_name || 'unknown'}

Return the optimized code and explain what you changed.`
};
const type = input.prompt ? 'code' : input.script && input.script_type ? 'lint' : input.error_message ? 'error' : 'query';
return [{ json: { type, prompt: prompts[type], original: input } }];

const ai = $input.first().json;
const prev = $('Build Prompt').first().json;
const content = ai.choices?.[0]?.message?.content || '';
const type = prev.type;
let result = { success: true, model: ai.model };
try {
  if (type === 'code') result.code = content;
  else if (type === 'error') {
    const parsed = JSON.parse(content.replace(/```json\n?/g,'').replace(/```/g,'').trim());
    Object.assign(result, parsed);
  } else if (type === 'lint') {
    const parsed = JSON.parse(content.replace(/```json\n?/g,'').replace(/```/g,'').trim());
    Object.assign(result, parsed);
  } else result.optimized = content;
} catch(e) {
  if (type === 'code') result.code = content;
  else result.answer = content;
}
return [{ json: result }];
